import 'package:bank_scan/Gold/core/constants/app_colors.dart';
import 'package:bank_scan/Gold/core/constants/app_text_styles.dart';
import 'package:bank_scan/Gold/core/network/gold_session.dart';
import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';

import '../../core/constants/app_routes.dart';
import '../../features/loans/screens/add_loan_screen.dart';

class QuickActionsModal extends StatelessWidget {
  const QuickActionsModal({super.key});

  static void show(BuildContext context) {
    showModalBottomSheet(
      context: context,
      backgroundColor: Colors.transparent,
      isScrollControlled: true,
      builder: (context) => const QuickActionsModal(),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      decoration: const BoxDecoration(
        color: AppColors.white,
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 24),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // Header with Title and Close Button
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 16),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: [
                const SizedBox(width: 32), // Spacer for centering
                Text(
                  'Add Records',
                  style: AppTextStyles.bodyLarge.copyWith(fontSize: 18),
                ),
                GestureDetector(
                  onTap: () => Navigator.pop(context),
                  child: Container(
                    padding: const EdgeInsets.all(4),
                    decoration: BoxDecoration(
                      color: AppColors.iconBackground.withOpacity(0.5),
                      shape: BoxShape.circle,
                    ),
                    child: const Icon(Icons.close, size: 18, color: AppColors.primaryBlue),
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(height: 16),
          const Divider(height: 1, thickness: 1, color: AppColors.divider),
          const SizedBox(height: 32),
          // Action Items Row
          Builder(
            builder: (context) {
              final hasExpensesWrite = GoldSession.instance.canWrite('Expenses');
              final hasGoldWrite = GoldSession.instance.canWrite('Gold');
              final hasLoanWrite = GoldSession.instance.canWrite('Loan');

              if (!hasExpensesWrite && !hasGoldWrite && !hasLoanWrite) {
                return const Padding(
                  padding: EdgeInsets.symmetric(vertical: 24),
                  child: Text(
                    'No write permissions granted for any module.',
                    style: TextStyle(
                      color: AppColors.textSecondary,
                      fontSize: 14,
                      fontWeight: FontWeight.w500,
                    ),
                  ),
                );
              }

              return Row(
                mainAxisAlignment: MainAxisAlignment.spaceEvenly,
                children: [
                  if (hasExpensesWrite)
                    _buildActionItem(
                      context: context,
                      svgString: _expensesSvg,
                      label: 'Expenses',
                      onTap: () {
                        Navigator.pop(context);
                        AppRoutes.push(context, AppRoutes.addExpense);
                      },
                    ),
                  if (hasGoldWrite)
                    _buildActionItem(
                      context: context,
                      svgString: _goldSvg,
                      label: 'Gold',
                      onTap: () {
                        Navigator.pop(context);
                        AppRoutes.push(context, AppRoutes.addGold);
                      },
                    ),
                  if (hasLoanWrite)
                    _buildActionItem(
                      context: context,
                      svgString: _loansSvg,
                      label: 'Loans',
                      onTap: () {
                        Navigator.pop(context);
                        Navigator.push(
                          context,
                          MaterialPageRoute(builder: (_) => const AddLoanScreen()),
                        );
                      },
                    ),
                ],
              );
            },
          ),
          const SizedBox(height: 40),
        ],
      ),
    );
  }

  Widget _buildActionItem({
    required BuildContext context,
    required String svgString,
    required String label,
    required VoidCallback onTap,
  }) {
    return GestureDetector(
      onTap: onTap,
      child: Column(
        children: [
          Container(
            width: 90,
            height: 90,
            decoration: BoxDecoration(
              color: AppColors.modalIconBackground,
              borderRadius: BorderRadius.circular(10),
            ),
            child: Center(
              child: SvgPicture.string(
                svgString,
                width: 40,
                height: 40,
                fit: BoxFit.contain,
              ),
            ), 
          ),
          const SizedBox(height: 12),
          Text(
            label,
            style: AppTextStyles.bodySmall.copyWith(
              fontWeight: FontWeight.w600,
              color: AppColors.textPrimary,
            ),
          ),
        ],
      ),
    );
  }
}

